+/// Resolve per-column collation for a `SELECT` statement's result columns.
+///
+/// For each result column, checks:
+/// 1. Explicit `COLLATE` on the expression
+/// 2. The declared collation of the referenced column in the table schema
+///
+/// Returns `None` for columns with default BINARY collation.
+fn select_result_collations(
+    select: &SelectStatement,
+    schemas: &[TableSchema],
+) -> Vec<Option<String>> {
+    let SelectCore::Select { columns, from, .. } = &select.body.select else {
+        return Vec::new();
+    };
+
+    // Collect table names from the FROM clause for Star/TableStar expansion.
+    let from_table_names: Vec<&str> = from
+        .as_ref()
+        .map(|f| collect_from_table_names(&f.source, &f.joins))
+        .unwrap_or_default();
+
+    let mut collations = Vec::new();
+    for col in columns {
+        match col {
+            ResultColumn::Expr { expr, .. } => {
+                collations.push(agg_arg_collation(expr, schemas));
+            }
+            ResultColumn::Star => {
+                // Expand star: all columns from all tables in FROM order.
+                for table_name in &from_table_names {
+                    if let Some(ts) = schemas
+                        .iter()
+                        .find(|s| s.name.eq_ignore_ascii_case(table_name))
+                    {
+                        for ci in &ts.columns {
+                            let coll = ci.collation.as_ref().and_then(|c| {
+                                if c.eq_ignore_ascii_case("BINARY") {
+                                    None
+                                } else {
+                                    Some(c.clone())
+                                }
+                            });
+                            collations.push(coll);
+                        }
+                    }
+                }
+            }
+            ResultColumn::TableStar(table) => {
+                if let Some(ts) = schemas.iter().find(|s| s.name.eq_ignore_ascii_case(table)) {
+                    for ci in &ts.columns {
+                        let coll = ci.collation.as_ref().and_then(|c| {
+                            if c.eq_ignore_ascii_case("BINARY") {
+                                None
+                            } else {
+                                Some(c.clone())
+                            }
+                        });
+                        collations.push(coll);
+                    }
+                }
+            }
+        }
+    }
+    collations
+}
