+/// Collect table names from a FROM clause (source + joins).
+fn collect_from_table_names<'a>(
+    source: &'a TableOrSubquery,
+    joins: &'a [fsqlite_ast::JoinClause],
+) -> Vec<&'a str> {
+    let mut names = Vec::new();
+    collect_table_or_subquery_names(source, &mut names);
+    for join in joins {
+        collect_table_or_subquery_names(&join.table, &mut names);
+    }
+    names
+}
+
+/// Recursively collect table names from a `TableOrSubquery`.
+fn collect_table_or_subquery_names<'a>(tos: &'a TableOrSubquery, names: &mut Vec<&'a str>) {
+    match tos {
+        TableOrSubquery::Table { name, .. } => {
+            names.push(&name.name);
+        }
+        TableOrSubquery::Subquery { .. } | TableOrSubquery::TableFunction { .. } => {}
+        TableOrSubquery::ParenJoin(inner) => {
+            collect_table_or_subquery_names(&inner.source, names);
+            for join in &inner.joins {
+                collect_table_or_subquery_names(&join.table, names);
+            }
+        }
+    }
+}
